mapper.select:
SELECT * FROM ( SELECT inner_q.*, ROWNUM AS rn FROM ( SELECT th.history_id, u.user_name, NVL(d_title.new_value, t.task_title) AS taskTitle, NVL(d_type.new_value, tt.type_name) AS typeName, cc.default_describe AS taskStatus, th.action_type, th.action_at + INTERVAL '9' HOUR AS actionAt FROM task_history th INNER JOIN task t ON th.task_id = t.task_id INNER JOIN users u ON th.changed_by = u.user_code INNER JOIN task_types tt ON t.type_id = tt.type_id LEFT JOIN task_history_detail d_title ON th.history_id = d_title.history_id AND d_title.field_name = 'task_title' LEFT JOIN task_history_detail d_type ON th.history_id = d_type.history_id AND d_type.field_name = 'type_name' LEFT JOIN common_code cc ON t.task_status = cc.common_id AND cc.common_code = '0E'
t.project_id = #{projectId}
AND u.user_code = #{userCode}
AND th.action_at >= TO_DATE(#{startDate}, 'YYYY.MM.DD') - INTERVAL '9' HOUR
AND th.action_at < TO_DATE(#{endDate}, 'YYYY.MM.DD') + INTERVAL '1' DAY - INTERVAL '9' HOUR
AND NVL(d_type.new_value, tt.type_name) IN
#{type}
ORDER BY th.action_at DESC ) inner_q WHERE ROWNUM <= #{offset} + #{pageSize} ) WHERE rn > #{offset}

SELECT COUNT(*) FROM task_history th LEFT JOIN task t ON th.task_id = t.task_id LEFT JOIN users u ON th.changed_by = u.user_code LEFT JOIN task_types tt ON t.type_id = tt.type_id LEFT JOIN task_history_detail d_type ON th.history_id = d_type.history_id AND d_type.field_name = 'type_name'
t.project_id = #{projectId}
AND u.user_code = #{userCode}
AND th.action_at >= TO_DATE(#{startDate}, 'YYYY.MM.DD') - INTERVAL '9' HOUR
AND th.action_at < TO_DATE(#{endDate}, 'YYYY.MM.DD') + INTERVAL '1' DAY - INTERVAL '9' HOUR
AND NVL(d_type.new_value, tt.type_name) IN
#{type}
